mapper.select:
SELECT COUNT(*)
FROM   chat_member
WHERE  chat_room_id = #{chatRoomId}
  AND  member_id    = #{memberId}

mapper.update:
UPDATE chat_member
SET    last_connected_at = CURRENT_TIMESTAMP
WHERE  chat_room_id = #{chatRoomId}
  AND  member_id    = #{memberId}

mapper.select:
SELECT * FROM ( SELECT cm.message_id, cm.room_id, cm.member_id, NVL(m2.nickname, '알 수 없음') AS nickname, m2.profile_image, cm.message_type, cm.content, TO_CHAR(cm.created_at, 'YYYY-MM-DD HH24:MI:SS') AS created_at FROM chat_message cm LEFT JOIN member2 m2 ON m2.member_id = cm.member_id WHERE cm.room_id = #{chatRoomId}
AND cm.message_id < #{beforeId}
ORDER BY cm.message_id DESC ) WHERE ROWNUM <= #{limit}

SELECT COUNT(*)
FROM   chat_message   cm
JOIN   chat_member    mb
       ON mb.chat_room_id = cm.room_id
      AND mb.member_id    = #{memberId}
WHERE  cm.room_id      = #{chatRoomId}
  AND  cm.created_at   > mb.last_connected_at
  AND  cm.member_id   != #{memberId}
  AND  cm.message_type = 'TALK'
